import React from 'react';

function WeeklyCalendar({ habit }) {
  const today = new Date();
  const days = [];
  for (let i = 6; i >= 0; i--) {
    const date = new Date(today);
    date.setDate(today.getDate() - i);
    days.push(date);
  }

  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

  return (
    <div className="flex justify-between">
      {days.map((date, index) => {
        const dateStr = date.toISOString().split('T')[0];
        const completed = habit.completions[dateStr];
        return (
          <div key={dateStr} className="text-center">
            <div className="text-sm text-gray-600">{dayNames[date.getDay()]}</div>
            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-white text-xs ${completed ? 'bg-green-500' : 'bg-red-500'}`}>
              {date.getDate()}
            </div>
          </div>
        );
      })}
    </div>
  );
}

export default WeeklyCalendar;
